{
  "name": "InventoryFlow",
  "description": "A modern, Google Sheets-integrated Inventory Management System with Inward/Outward tracking, Master data management, and AI-powered stock insights."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import { InventoryProvider } from './context/InventoryContext';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <InventoryProvider>
      <App />
    </InventoryProvider>
  </React.StrictMode>
);

export interface Item {
  code: string;
  name: string;
  category: string;
  openingStock: number;
  currentStock: number;
  uom: string; // Unit of Measure
}

export enum TransactionType {
  INWARD = 'INWARD',
  OUTWARD = 'OUTWARD'
}

export interface LogEntry {
  id: string;
  date: string; // ISO String
  itemCode: string;
  itemName: string;
  type: TransactionType;
  quantity: number;
  partyName: string; // Supplier for Inward, Customer for Outward
  stockAfter: number;
}

export interface DashboardStats {
  totalItems: number;
  totalStock: number;
  lowStockItems: number;
  recentActivityCount: number;
}

export const CATEGORIES = [
  'Electronics',
  'Furniture',
  'Stationery',
  'Groceries',
  'Clothing',
  'Raw Materials',
  'Others'
];

export const UNITS = ['pcs', 'kg', 'ltr', 'box', 'm', 'set'];

import { GoogleGenAI } from "@google/genai";
import { Item, LogEntry } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const generateInventoryInsight = async (items: Item[], logs: LogEntry[]): Promise<string> => {
  const ai = getAiClient();
  if (!ai) {
    return "API Key not configured. Please set process.env.API_KEY to use AI insights.";
  }

  // Filter for critical data to reduce token usage
  const lowStockItems = items.filter(i => i.currentStock < 10).map(i => `${i.name} (${i.currentStock} ${i.uom})`);
  const recentLogs = logs.slice(0, 10).map(l => `${l.type}: ${l.quantity} ${l.itemName}`);

  const prompt = `
    Analyze this inventory data and provide a brief, actionable executive summary (max 3 bullet points).

    Low Stock Items: ${lowStockItems.join(', ') || 'None'}
    Recent Activity: ${recentLogs.join(', ')}
    Total SKU Count: ${items.length}

    Focus on reordering needs and unusual movement patterns. Be professional.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Unable to generate insights at this time.";
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Item, LogEntry, TransactionType } from '../types';

interface InventoryContextType {
  items: Item[];
  logs: LogEntry[];
  addItem: (item: Item) => void;
  updateItem: (code: string, updates: Partial<Item>) => void;
  processInward: (data: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => Promise<void>;
  processOutward: (data: { itemCode: string; quantity: number; customer: string }) => Promise<void>;
  exportData: () => void;
}

const InventoryContext = createContext<InventoryContextType | undefined>(undefined);

// Mock Initial Data
const INITIAL_ITEMS: Item[] = [
  { code: 'IT001', name: 'Laptop Dell XPS', category: 'Electronics', openingStock: 10, currentStock: 8, uom: 'pcs' },
  { code: 'IT002', name: 'Office Chair', category: 'Furniture', openingStock: 50, currentStock: 45, uom: 'pcs' },
  { code: 'IT003', name: 'A4 Paper Rim', category: 'Stationery', openingStock: 100, currentStock: 12, uom: 'box' },
];

export const InventoryProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [items, setItems] = useState<Item[]>(INITIAL_ITEMS);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Simulate loading from Google Sheets
  useEffect(() => {
    // In a real app, this would fetch from the Google Apps Script Web App URL
    console.log('Inventory System Initialized');
  }, []);

  const addItem = (newItem: Item) => {
    setItems(prev => [...prev, newItem]);
  };

  const updateItem = (code: string, updates: Partial<Item>) => {
    setItems(prev => prev.map(item => item.code === code ? { ...item, ...updates } : item));
  };

  const processInward = async ({ itemCode, quantity, supplier, newItemDetails }: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => {
    // Simulate Network Delay
    await new Promise(resolve => setTimeout(resolve, 500));

    let currentItem = items.find(i => i.code === itemCode);
    let stockAfter = quantity;

    if (currentItem) {
      stockAfter = currentItem.currentStock + quantity;
      updateItem(itemCode, { currentStock: stockAfter });
    } else if (newItemDetails && newItemDetails.name && newItemDetails.category) {
      // New Item Logic
      const newItem: Item = {
        code: itemCode,
        name: newItemDetails.name,
        category: newItemDetails.category,
        uom: newItemDetails.uom || 'pcs',
        openingStock: 0,
        currentStock: quantity
      };
      addItem(newItem);
      currentItem = newItem;
      stockAfter = quantity;
    } else {
      throw new Error("Item not found and no new item details provided.");
    }

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem ? currentItem.name : newItemDetails?.name || 'Unknown',
      type: TransactionType.INWARD,
      quantity,
      partyName: supplier,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const processOutward = async ({ itemCode, quantity, customer }: { itemCode: string; quantity: number; customer: string }) => {
    await new Promise(resolve => setTimeout(resolve, 500));

    const currentItem = items.find(i => i.code === itemCode);
    if (!currentItem) throw new Error("Item not found.");

    if (currentItem.currentStock < quantity) {
      throw new Error(`Insufficient stock! Available: ${currentItem.currentStock}`);
    }

    const stockAfter = currentItem.currentStock - quantity;
    updateItem(itemCode, { currentStock: stockAfter });

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem.name,
      type: TransactionType.OUTWARD,
      quantity,
      partyName: customer,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const exportData = () => {
    // Simple CSV export implementation
    const headers = ["Date", "Type", "Item Code", "Name", "Quantity", "Party", "Stock After"];
    const rows = logs.map(log => [
      new Date(log.date).toLocaleString(),
      log.type,
      log.itemCode,
      log.itemName,
      log.quantity,
      log.partyName,
      log.stockAfter
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(","), ...rows.map(e => e.join(","))].join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "inventory_logs.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <InventoryContext.Provider value={{ items, logs, addItem, updateItem, processInward, processOutward, exportData }}>
      {children}
    </InventoryContext.Provider>
  );
};

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) throw new Error("useInventory must be used within InventoryProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { useInventory } from '../context/InventoryContext';
import { generateInventoryInsight } from '../services/geminiService';
import { Package, AlertTriangle, Activity, TrendingUp, Sparkles, Loader2 } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

export const Dashboard: React.FC = () => {
  const { items, logs } = useInventory();
  const [insight, setInsight] = useState<string>('');
  const [loadingInsight, setLoadingInsight] = useState(false);

  const totalStock = items.reduce((acc, item) => acc + item.currentStock, 0);
  const lowStockCount = items.filter(item => item.currentStock < 15).length;

  // Data for chart (Top 5 items by stock)
  const chartData = [...items]
    .sort((a, b) => b.currentStock - a.currentStock)
    .slice(0, 5)
    .map(item => ({
      name: item.name.length > 10 ? item.name.substring(0, 10) + '...' : item.name,
      stock: item.currentStock
    }));

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    const result = await generateInventoryInsight(items, logs);
    setInsight(result);
    setLoadingInsight(false);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Stat Cards */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
            <Package size={24} />
          </div>
          <div>
            <p className="text-gray-500 text-sm">Total Stock Units</p>
            <h3 className="text-2xl font-bold text-gray-800">{totalStock}</h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4">
          <div className="p-3 bg-red-100 text-red-600 rounded-full">
            <AlertTriangle size={24} />
          </div>
          <div>
            <p className="text-gray-500 text-sm">Low Stock Alerts</p>
            <h3 className="text-2xl font-bold text-gray-800">{lowStockCount}</h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4">
          <div className="p-3 bg-green-100 text-green-600 rounded-full">
            <Activity size={24} />
          </div>
          <div>
            <p className="text-gray-500 text-sm">Recent Transactions</p>
            <h3 className="text-2xl font-bold text-gray-800">{logs.length}</h3>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
            <TrendingUp size={20} className="mr-2 text-gray-500" />
            Top Inventory Items
          </h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                  cursor={{ fill: '#F3F4F6' }}
                />
                <Bar dataKey="stock" fill="#3B82F6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* AI Insight */}
        <div className="bg-gradient-to-br from-indigo-50 to-purple-50 p-6 rounded-xl shadow-sm border border-indigo-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-indigo-900 flex items-center">
              <Sparkles size={20} className="mr-2 text-indigo-500" />
              AI Stock Analyst
            </h3>
            <button 
              onClick={handleGenerateInsight}
              disabled={loadingInsight}
              className="px-3 py-1 bg-white hover:bg-indigo-50 text-indigo-600 text-xs font-medium rounded-md border border-indigo-200 transition-colors flex items-center"
            >
              {loadingInsight ? <Loader2 size={12} className="animate-spin mr-1" /> : null}
              {insight ? 'Refresh' : 'Generate'}
            </button>
          </div>
          <div className="text-sm text-indigo-800 leading-relaxed min-h-[200px]">
            {insight ? (
              <div className="whitespace-pre-line">{insight}</div>
            ) : (
              <p className="text-indigo-400 italic text-center mt-10">
                Click generate to let Gemini analyze your inventory health, stock levels, and suggest reordering strategies.
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useInventory } from '../context/InventoryContext';
import { CATEGORIES, UNITS } from '../types';
import { Save, PlusCircle, CheckCircle } from 'lucide-react';

export const InwardForm: React.FC = () => {
  const { items, processInward } = useInventory();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const [itemCode, setItemCode] = useState('');
  const [itemName, setItemName] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [qty, setQty] = useState('');
  const [supplier, setSupplier] = useState('');
  const [uom, setUom] = useState(UNITS[0]);
  const [isNewItem, setIsNewItem] = useState(false);
  const [existingStock, setExistingStock] = useState<number | null>(null);

  // Auto-fill logic
  useEffect(() => {
    const foundItem = items.find(i => i.code === itemCode);
    if (foundItem) {
      setItemName(foundItem.name);
      setCategory(foundItem.category);
      setUom(foundItem.uom);
      setExistingStock(foundItem.currentStock);
      setIsNewItem(false);
    } else {
      // If code has length but not found, assumes potential new item
      if (itemCode.length > 2) {
        setIsNewItem(true);
        setExistingStock(null);
        // Don't clear name/category immediately to allow typing
      }
    }
  }, [itemCode, items]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await processInward({
        itemCode,
        quantity: Number(qty),
        supplier,
        newItemDetails: isNewItem ? { name: itemName, category, uom } : undefined
      });
      setSuccess(true);
      // Reset form
      setItemCode('');
      setItemName('');
      setQty('');
      setSupplier('');
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      alert("Error processing inward: " + err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="bg-emerald-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-semibold text-lg flex items-center">
          <PlusCircle className="mr-2" /> Inward Stock Entry
        </h2>
        <span className="text-emerald-100 text-sm bg-emerald-700 px-2 py-1 rounded">
          {new Date().toLocaleDateString()}
        </span>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Item Code</label>
            <input 
              type="text" 
              list="item-codes"
              required
              value={itemCode}
              onChange={(e) => setItemCode(e.target.value.toUpperCase())}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
              placeholder="Scan or type code"
            />
            <datalist id="item-codes">
              {items.map(i => <option key={i.code} value={i.code} />)}
            </datalist>
            {isNewItem && itemCode.length > 2 && (
              <p className="text-xs text-blue-600 mt-1">New Item Detected - Please fill details</p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Item Name</label>
            <input 
              type="text" 
              required
              value={itemName}
              readOnly={!isNewItem}
              onChange={(e) => setItemName(e.target.value)}
              className={`w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none ${!isNewItem ? 'bg-gray-100' : ''}`}
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
            <select 
              disabled={!isNewItem}
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 bg-white disabled:bg-gray-100"
            >
              {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>

          <div>
             <label className="block text-sm font-medium text-gray-700 mb-1">Unit (UoM)</label>
             <select
               disabled={!isNewItem}
               value={uom}
               onChange={(e) => setUom(e.target.value)}
               className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 bg-white disabled:bg-gray-100"
             >
                {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
             </select>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 border-t pt-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Quantity In</label>
            <input 
              type="number" 
              required
              min="1"
              value={qty}
              onChange={(e) => setQty(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
            />
            {existingStock !== null && (
              <p className="text-xs text-gray-500 mt-1">Current Stock: {existingStock}</p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Supplier / Vendor</label>
            <input 
              type="text" 
              required
              value={supplier}
              onChange={(e) => setSupplier(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
              placeholder="e.g. Acme Corp"
            />
          </div>
        </div>

        <button 
          type="submit"
          disabled={loading}
          className="w-full mt-4 bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-3 rounded-lg transition-colors flex justify-center items-center disabled:opacity-70"
        >
          {loading ? (
             <span className="flex items-center">Saving...</span>
          ) : success ? (
             <span className="flex items-center"><CheckCircle className="mr-2"/> Stock Added Successfully</span>
          ) : (
             <span className="flex items-center"><Save className="mr-2" size={18}/> Save to Inventory</span>
          )}
        </button>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useInventory } from '../context/InventoryContext';
import { LogOut, CheckCircle, AlertCircle } from 'lucide-react';

export const OutwardForm: React.FC = () => {
  const { items, processOutward } = useInventory();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [itemCode, setItemCode] = useState('');
  const [itemName, setItemName] = useState('');
  const [qty, setQty] = useState('');
  const [customer, setCustomer] = useState('');
  const [currentStock, setCurrentStock] = useState<number>(0);
  const [uom, setUom] = useState('');

  // Auto-fill logic
  useEffect(() => {
    const foundItem = items.find(i => i.code === itemCode);
    if (foundItem) {
      setItemName(foundItem.name);
      setCurrentStock(foundItem.currentStock);
      setUom(foundItem.uom);
      setError(null);
    } else {
      setItemName('');
      setCurrentStock(0);
      setUom('');
    }
  }, [itemCode, items]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (Number(qty) > currentStock) {
      setError(`Cannot issue ${qty}. Only ${currentStock} ${uom} available.`);
      return;
    }

    setLoading(true);
    try {
      await processOutward({
        itemCode,
        quantity: Number(qty),
        customer,
      });
      setSuccess(true);
      // Reset form
      setItemCode('');
      setQty('');
      setCustomer('');
      setTimeout(() => setSuccess(false), 3000);
    } catch (err: any) {
      setError(err.message || "Error processing outward");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="bg-orange-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-semibold text-lg flex items-center">
          <LogOut className="mr-2" /> Outward / Issue Stock
        </h2>
        <span className="text-orange-100 text-sm bg-orange-700 px-2 py-1 rounded">
          {new Date().toLocaleDateString()}
        </span>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-4">
        {error && (
          <div className="bg-red-50 text-red-700 p-3 rounded-lg flex items-center text-sm">
            <AlertCircle size={16} className="mr-2" /> {error}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Select Item</label>
            <select 
              required
              value={itemCode}
              onChange={(e) => setItemCode(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:outline-none bg-white"
            >
              <option value="">-- Choose Item --</option>
              {items.map(i => <option key={i.code} value={i.code}>{i.code} - {i.name}</option>)}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Item Name</label>
            <input 
              type="text" 
              disabled
              value={itemName}
              className="w-full p-2 border border-gray-300 rounded-lg bg-gray-100"
            />
          </div>
        </div>

        <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
          <div className="flex justify-between items-center text-sm text-gray-600">
            <span>Available Stock:</span>
            <span className={`font-bold text-lg ${currentStock === 0 ? 'text-red-600' : 'text-gray-800'}`}>
              {currentStock} <span className="text-xs font-normal">{uom}</span>
            </span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Quantity Out</label>
            <input 
              type="number" 
              required
              min="1"
              max={currentStock}
              value={qty}
              onChange={(e) => setQty(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:outline-none"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Customer / Department</label>
            <input 
              type="text" 
              required
              value={customer}
              onChange={(e) => setCustomer(e.target.value)}
              className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:outline-none"
              placeholder="e.g. Sales Dept"
            />
          </div>
        </div>

        <button 
          type="submit"
          disabled={loading || currentStock === 0}
          className="w-full mt-4 bg-orange-600 hover:bg-orange-700 text-white font-medium py-3 rounded-lg transition-colors flex justify-center items-center disabled:opacity-70 disabled:cursor-not-allowed"
        >
          {loading ? (
