import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Item, LogEntry, TransactionType } from '../types';

interface InventoryContextType {
  items: Item[];
  logs: LogEntry[];
  addItem: (item: Item) => void;
  updateItem: (code: string, updates: Partial<Item>) => void;
  importItems: (newItems: Item[]) => void;
  processInward: (data: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => Promise<void>;
  processOutward: (data: { itemCode: string; quantity: number; customer: string }) => Promise<void>;
  exportData: () => void;
}

const InventoryContext = createContext<InventoryContextType | undefined>(undefined);

// Mock Initial Data
const INITIAL_ITEMS: Item[] = [
  { code: 'IT001', name: 'Laptop Dell XPS', category: 'Electronics', openingStock: 10, currentStock: 8, uom: 'pcs' },
  { code: 'IT002', name: 'Office Chair', category: 'Furniture', openingStock: 50, currentStock: 45, uom: 'pcs' },
  { code: 'IT003', name: 'A4 Paper Rim', category: 'Stationery', openingStock: 100, currentStock: 12, uom: 'box' },
];

export const InventoryProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [items, setItems] = useState<Item[]>(INITIAL_ITEMS);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Simulate loading from Google Sheets
  useEffect(() => {
    // In a real app, this would fetch from the Google Apps Script Web App URL
    console.log('Inventory System Initialized');
  }, []);

  const addItem = (newItem: Item) => {
    setItems(prev => [...prev, newItem]);
  };

  const updateItem = (code: string, updates: Partial<Item>) => {
    setItems(prev => prev.map(item => item.code === code ? { ...item, ...updates } : item));
  };

  const importItems = (newItems: Item[]) => {
    setItems(prevItems => {
      const itemMap = new Map(prevItems.map(i => [i.code, i]));

      newItems.forEach(item => {
        if (item.code) {
          const existing = itemMap.get(item.code);
          if (existing) {
            // Update existing item fields, keep current stock if not explicitly meant to overwrite,
            // but for master import usually we want to update metadata. 
            // If "Current Stock" is in Excel, it overwrites.
            itemMap.set(item.code, { ...existing, ...item });
          } else {
            // Add new item
            itemMap.set(item.code, item);
          }
        }
      });

      return Array.from(itemMap.values());
    });
  };

  const processInward = async ({ itemCode, quantity, supplier, newItemDetails }: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => {
    // Simulate Network Delay
    await new Promise(resolve => setTimeout(resolve, 500));

    let currentItem = items.find(i => i.code === itemCode);
    let stockAfter = quantity;

    if (currentItem) {
      stockAfter = currentItem.currentStock + quantity;
      updateItem(itemCode, { currentStock: stockAfter });
    } else if (newItemDetails && newItemDetails.name && newItemDetails.category) {
      // New Item Logic
      const newItem: Item = {
        code: itemCode,
        name: newItemDetails.name,
        category: newItemDetails.category,
        uom: newItemDetails.uom || 'pcs',
        openingStock: 0,
        currentStock: quantity
      };
      addItem(newItem);
      currentItem = newItem;
      stockAfter = quantity;
    } else {
      throw new Error("Item not found and no new item details provided.");
    }

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem ? currentItem.name : newItemDetails?.name || 'Unknown',
      type: TransactionType.INWARD,
      quantity,
      partyName: supplier,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const processOutward = async ({ itemCode, quantity, customer }: { itemCode: string; quantity: number; customer: string }) => {
    await new Promise(resolve => setTimeout(resolve, 500));

    const currentItem = items.find(i => i.code === itemCode);
    if (!currentItem) throw new Error("Item not found.");

    if (currentItem.currentStock < quantity) {
      throw new Error(`Insufficient stock! Available: ${currentItem.currentStock}`);
    }

    const stockAfter = currentItem.currentStock - quantity;
    updateItem(itemCode, { currentStock: stockAfter });

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem.name,
      type: TransactionType.OUTWARD,
      quantity,
      partyName: customer,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const exportData = () => {
    // Simple CSV export implementation
    const headers = ["Date", "Type", "Item Code", "Name", "Quantity", "Party", "Stock After"];
    const rows = logs.map(log => [
      new Date(log.date).toLocaleString(),
      log.type,
      log.itemCode,
      log.itemName,
      log.quantity,
      log.partyName,
      log.stockAfter
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(","), ...rows.map(e => e.join(","))].join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "inventory_logs.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <InventoryContext.Provider value={{ items, logs, addItem, updateItem, importItems, processInward, processOutward, exportData }}>
      {children}
    </InventoryContext.Provider>
  );
};

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) throw new Error("useInventory must be used within InventoryProvider");
  return context;
};

import React, { useState, useRef } from 'react';
import { useInventory } from '../context/InventoryContext';
import { Search, Edit2, Save, X, UploadCloud, FileSpreadsheet } from 'lucide-react';
import { Item } from '../types';
import * as XLSX from 'xlsx';

export const MasterList: React.FC = () => {
  const { items, updateItem, importItems } = useInventory();
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Item>>({});
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filteredItems = items.filter(i => 
    i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.code.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const startEdit = (item: Item) => {
    setEditingId(item.code);
    setEditForm(item);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEdit = (code: string) => {
    updateItem(code, editForm);
    setEditingId(null);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>, field: keyof Item) => {
    setEditForm(prev => ({ ...prev, [field]: e.target.value }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = new Uint8Array(evt.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const wsname = workbook.SheetNames[0];
        const ws = workbook.Sheets[wsname];
        const jsonData = XLSX.utils.sheet_to_json(ws);

        if (jsonData.length === 0) {
          alert("Sheet is empty!");
          return;
        }

        // Map loosely matched columns to Item interface
        const parsedItems: Item[] = jsonData.map((row: any) => {
          // Normalize keys to lowercase for flexible matching
          const normalizedRow: any = {};
          Object.keys(row).forEach(key => {
            normalizedRow[key.toLowerCase().trim()] = row[key];
          });

          return {
            code: normalizedRow['item code'] || normalizedRow['code'] || normalizedRow['id'] || '',
            name: normalizedRow['item name'] || normalizedRow['name'] || normalizedRow['item'] || '',
            category: normalizedRow['category'] || 'General',
            uom: normalizedRow['uom'] || normalizedRow['unit'] || 'pcs',
            openingStock: Number(normalizedRow['opening stock'] || normalizedRow['opening'] || 0),
            currentStock: Number(normalizedRow['current stock'] || normalizedRow['stock'] || normalizedRow['quantity'] || normalizedRow['opening stock'] || 0)
          };
        }).filter(i => i.code && i.name); // Valid items only

        if (parsedItems.length > 0) {
          importItems(parsedItems);
          alert(`Successfully imported ${parsedItems.length} items from Excel.`);
        } else {
          alert('No valid items found. Ensure columns like "Item Code" and "Item Name" exist.');
        }

      } catch (error) {
        console.error("Import Error:", error);
        alert("Failed to parse Excel file. Please check the format.");
      } finally {
        // Reset input
        if (fileInputRef.current) fileInputRef.current.value = "";
      }
    };
    reader.readAsArrayBuffer(file);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-4 border-b border-gray-100 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center space-x-2">
          <h3 className="text-lg font-semibold text-gray-800">Master Inventory List</h3>
          <span className="bg-gray-100 text-gray-500 text-xs px-2 py-1 rounded-full">{items.length} Items</span>
        </div>

        <div className="flex items-center space-x-3 w-full md:w-auto">
          {/* File Upload Trigger */}
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            accept=".xlsx, .xls, .csv" 
            className="hidden" 
          />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center space-x-2 bg-green-600 hover:bg-green-700 text-white px-3 py-2 rounded-lg text-sm font-medium transition-colors"
          >
            <FileSpreadsheet size={16} />
            <span className="hidden sm:inline">Import Excel</span>
            <span className="sm:hidden">Import</span>
          </button>

          <div className="relative flex-1 md:flex-none md:w-64">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
            <input 
              type="text" 
              placeholder="Search item code or name..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm text-gray-600">
          <thead className="bg-gray-50 text-gray-800 font-medium">
            <tr>
              <th className="p-4">Item Code</th>
              <th className="p-4">Item Name</th>
              <th className="p-4">Category</th>
              <th className="p-4">UoM</th>
              <th className="p-4 text-right">Stock</th>
              <th className="p-4 text-center">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {filteredItems.length === 0 ? (
              <tr>
                <td colSpan={6} className="p-12 text-center flex flex-col items-center justify-center text-gray-400">
                  <UploadCloud size={48} className="mb-2 opacity-20" />
                  <p>No items found.</p>
                  <button onClick={() => fileInputRef.current?.click()} className="text-blue-500 hover:underline mt-1">
                    Import data from Excel?
                  </button>
                </td>
              </tr>
            ) : (
              filteredItems.map(item => (
                <tr key={item.code} className="hover:bg-gray-50 transition-colors">
                  <td className="p-4 font-medium text-gray-900">{item.code}</td>

                  {/* Name */}
                  <td className="p-4">
                    {editingId === item.code ? (
                      <input 
                        className="border p-1.5 rounded w-full focus:ring-2 focus:ring-blue-500 focus:outline-none" 
                        value={editForm.name || ''} 
                        onChange={(e) => handleChange(e, 'name')}
                      />
                    ) : item.name}
                  </td>

                  {/* Category */}
                  <td className="p-4">
                     {editingId === item.code ? (
                      <input 
                        className="border p-1.5 rounded w-full focus:ring-2 focus:ring-blue-500 focus:outline-none" 
                        value={editForm.category || ''} 
                        onChange={(e) => handleChange(e, 'category')}
                      />
                    ) : (
                      <span className="bg-gray-100 text-gray-600 px-2 py-1 rounded text-xs border border-gray-200">{item.category}</span>
                    )}
                  </td>

                  {/* UoM */}
                   <td className="p-4 text-gray-500">
                    {item.uom}
                  </td>

                  {/* Stock (Read Only) */}
                  <td className={`p-4 text-right font-bold ${item.currentStock < 10 ? 'text-red-500' : 'text-gray-800'}`}>
                    {item.currentStock}
                  </td>

                  {/* Actions */}
                  <td className="p-4 text-center">
                    {editingId === item.code ? (
                      <div className="flex justify-center space-x-2">
                        <button onClick={() => saveEdit(item.code)} className="text-green-600 hover:bg-green-100 p-2 rounded-lg transition-colors"><Save size={16} /></button>
                        <button onClick={cancelEdit} className="text-red-600 hover:bg-red-100 p-2 rounded-lg transition-colors"><X size={16} /></button>
                      </div>
                    ) : (
                      <button onClick={() => startEdit(item)} className="text-blue-600 hover:bg-blue-100 p-2 rounded-lg transition-colors">
                        <Edit2 size={16} />
                      </button>
                    )}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

