export interface Item {
  code: string;
  name: string;
  category: string;
  openingStock: number;
  currentStock: number;
  uom: string; // Unit of Measure
}

export enum TransactionType {
  INWARD = 'INWARD',
  OUTWARD = 'OUTWARD'
}

export interface LogEntry {
  id: string;
  date: string; // ISO String
  itemCode: string;
  itemName: string;
  type: TransactionType;
  quantity: number;
  partyName: string; // Supplier for Inward, Customer for Outward
  stockAfter: number;
}

export interface DashboardStats {
  totalItems: number;
  totalStock: number;
  lowStockItems: number;
  recentActivityCount: number;
}

export interface InwardEntry {
  itemCode: string;
  quantity: number;
  supplier: string;
  newItemDetails?: {
    name?: string;
    category?: string;
    uom?: string;
  };
}

export const CATEGORIES = [
  'Electronics',
  'Furniture',
  'Stationery',
  'Groceries',
  'Clothing',
  'Raw Materials',
  'Others'
];

export const UNITS = ['pcs', 'kg', 'ltr', 'box', 'm', 'set'];

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Item, LogEntry, TransactionType, InwardEntry } from '../types';

interface InventoryContextType {
  items: Item[];
  logs: LogEntry[];
  addItem: (item: Item) => void;
  updateItem: (code: string, updates: Partial<Item>) => void;
  importItems: (newItems: Item[]) => void;
  processInward: (data: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => Promise<void>;
  processBulkInward: (entries: InwardEntry[]) => Promise<{ successCount: number; errorCount: number; errors: string[] }>;
  processOutward: (data: { itemCode: string; quantity: number; customer: string }) => Promise<void>;
  exportData: () => void;
}

const InventoryContext = createContext<InventoryContextType | undefined>(undefined);

// Mock Initial Data
const INITIAL_ITEMS: Item[] = [
  { code: 'IT001', name: 'Laptop Dell XPS', category: 'Electronics', openingStock: 10, currentStock: 8, uom: 'pcs' },
  { code: 'IT002', name: 'Office Chair', category: 'Furniture', openingStock: 50, currentStock: 45, uom: 'pcs' },
  { code: 'IT003', name: 'A4 Paper Rim', category: 'Stationery', openingStock: 100, currentStock: 12, uom: 'box' },
];

export const InventoryProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [items, setItems] = useState<Item[]>(INITIAL_ITEMS);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Simulate loading from Google Sheets
  useEffect(() => {
    // In a real app, this would fetch from the Google Apps Script Web App URL
    console.log('Inventory System Initialized');
  }, []);

  const addItem = (newItem: Item) => {
    setItems(prev => [...prev, newItem]);
  };

  const updateItem = (code: string, updates: Partial<Item>) => {
    setItems(prev => prev.map(item => item.code === code ? { ...item, ...updates } : item));
  };

  const importItems = (newItems: Item[]) => {
    setItems(prevItems => {
      const itemMap = new Map(prevItems.map(i => [i.code, i]));

      newItems.forEach(item => {
        if (item.code) {
          const existing = itemMap.get(item.code);
          if (existing) {
            // Update existing item fields, keep current stock if not explicitly meant to overwrite,
            // but for master import usually we want to update metadata. 
            // If "Current Stock" is in Excel, it overwrites.
            itemMap.set(item.code, { ...existing, ...item });
          } else {
            // Add new item
            itemMap.set(item.code, item);
          }
        }
      });

      return Array.from(itemMap.values());
    });
  };

  const processInward = async ({ itemCode, quantity, supplier, newItemDetails }: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => {
    // Simulate Network Delay
    await new Promise(resolve => setTimeout(resolve, 500));

    let currentItem = items.find(i => i.code === itemCode);
    let stockAfter = quantity;

    if (currentItem) {
      stockAfter = currentItem.currentStock + quantity;
      updateItem(itemCode, { currentStock: stockAfter });
    } else if (newItemDetails && newItemDetails.name && newItemDetails.category) {
      // New Item Logic
      const newItem: Item = {
        code: itemCode,
        name: newItemDetails.name,
        category: newItemDetails.category,
        uom: newItemDetails.uom || 'pcs',
        openingStock: 0,
        currentStock: quantity
      };
      addItem(newItem);
      currentItem = newItem;
      stockAfter = quantity;
    } else {
      throw new Error("Item not found and no new item details provided.");
    }

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem ? currentItem.name : newItemDetails?.name || 'Unknown',
      type: TransactionType.INWARD,
      quantity,
      partyName: supplier,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const processBulkInward = async (entries: InwardEntry[]) => {
    // Simulate Batch Network Delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    let successCount = 0;
    let errorCount = 0;
    const errors: string[] = [];
    const newLogs: LogEntry[] = [];

    // We update state based on current items to ensure we handle the batch atomically
    let currentItemsMap = new Map(items.map(i => [i.code, i]));

    entries.forEach((entry, index) => {
      try {
        if (!entry.itemCode || !entry.quantity || !entry.supplier) {
           throw new Error(`Row ${index + 1}: Missing required fields`);
        }

        const existingItem = currentItemsMap.get(entry.itemCode);
        let stockAfter = entry.quantity;
        let itemName = 'Unknown';

        if (existingItem) {
          stockAfter = existingItem.currentStock + entry.quantity;
          const updatedItem = { ...existingItem, currentStock: stockAfter };
          currentItemsMap.set(entry.itemCode, updatedItem);
          itemName = existingItem.name;
        } else {
          // New Item Logic for Bulk
          if (entry.newItemDetails && entry.newItemDetails.name) {
             const newItem: Item = {
               code: entry.itemCode,
               name: entry.newItemDetails.name,
               category: entry.newItemDetails.category || 'General',
               uom: entry.newItemDetails.uom || 'pcs',
               openingStock: 0,
               currentStock: entry.quantity
             };
             currentItemsMap.set(entry.itemCode, newItem);
             stockAfter = entry.quantity;
             itemName = newItem.name;
          } else {
            throw new Error(`Row ${index + 1}: Item '${entry.itemCode}' not found and no name provided.`);
          }
        }

        newLogs.push({
          id: Date.now().toString() + Math.random().toString().slice(2, 8),
          date: new Date().toISOString(),
          itemCode: entry.itemCode,
          itemName: itemName,
          type: TransactionType.INWARD,
          quantity: entry.quantity,
          partyName: entry.supplier,
          stockAfter
        });

        successCount++;
      } catch (err: any) {
        errorCount++;
        errors.push(err.message);
      }
    });

    // Update States
    setItems(Array.from(currentItemsMap.values()));
    setLogs(prev => [...newLogs, ...prev]);

    return { successCount, errorCount, errors };
  };

  const processOutward = async ({ itemCode, quantity, customer }: { itemCode: string; quantity: number; customer: string }) => {
    await new Promise(resolve => setTimeout(resolve, 500));

    const currentItem = items.find(i => i.code === itemCode);
    if (!currentItem) throw new Error("Item not found.");

    if (currentItem.currentStock < quantity) {
      throw new Error(`Insufficient stock! Available: ${currentItem.currentStock}`);
    }

    const stockAfter = currentItem.currentStock - quantity;
    updateItem(itemCode, { currentStock: stockAfter });

    const newLog: LogEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      itemCode,
      itemName: currentItem.name,
      type: TransactionType.OUTWARD,
      quantity,
      partyName: customer,
      stockAfter
    };

    setLogs(prev => [newLog, ...prev]);
  };

  const exportData = () => {
    // Simple CSV export implementation
    const headers = ["Date", "Type", "Item Code", "Name", "Quantity", "Party", "Stock After"];
    const rows = logs.map(log => [
      new Date(log.date).toLocaleString(),
      log.type,
      log.itemCode,
      log.itemName,
      log.quantity,
      log.partyName,
      log.stockAfter
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(","), ...rows.map(e => e.join(","))].join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "inventory_logs.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <InventoryContext.Provider value={{ items, logs, addItem, updateItem, importItems, processInward, processBulkInward, processOutward, exportData }}>
      {children}
    </InventoryContext.Provider>
  );
};

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) throw new Error("useInventory must be used within InventoryProvider");
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { useInventory } from '../context/InventoryContext';
import { CATEGORIES, UNITS, InwardEntry } from '../types';
import { Save, PlusCircle, CheckCircle, FileSpreadsheet, Download, Upload, AlertCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

export const InwardForm: React.FC = () => {
  const { items, processInward, processBulkInward } = useInventory();

  // Tab State
  const [activeTab, setActiveTab] = useState<'single' | 'bulk'>('single');

  // Single Entry State
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [itemCode, setItemCode] = useState('');
  const [itemName, setItemName] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [qty, setQty] = useState('');
  const [supplier, setSupplier] = useState('');
  const [uom, setUom] = useState(UNITS[0]);
  const [isNewItem, setIsNewItem] = useState(false);
  const [existingStock, setExistingStock] = useState<number | null>(null);

  // Bulk Import State
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [bulkLoading, setBulkLoading] = useState(false);
  const [bulkResult, setBulkResult] = useState<{ success: number; errors: number; msg: string[] } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-fill logic for Single Entry
  useEffect(() => {
    const foundItem = items.find(i => i.code === itemCode);
    if (foundItem) {
      setItemName(foundItem.name);
      setCategory(foundItem.category);
      setUom(foundItem.uom);
      setExistingStock(foundItem.currentStock);
      setIsNewItem(false);
    } else {
      if (itemCode.length > 2) {
        setIsNewItem(true);
        setExistingStock(null);
      }
    }
  }, [itemCode, items]);

  // Handle Single Entry Submit
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await processInward({
        itemCode,
        quantity: Number(qty),
        supplier,
        newItemDetails: isNewItem ? { name: itemName, category, uom } : undefined
      });
      setSuccess(true);
      setItemCode('');
      setItemName('');
      setQty('');
      setSupplier('');
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      alert("Error processing inward: " + err);
    } finally {
      setLoading(false);
    }
  };

  // Handle Template Download
  const downloadTemplate = () => {
    const ws = XLSX.utils.json_to_sheet([
      { 'Item Code': 'IT001', 'Quantity': 10, 'Supplier': 'Vendor A', 'Item Name (Optional)': '', 'Category (Optional)': '', 'UoM (Optional)': '' },
      { 'Item Code': 'NEW001', 'Quantity': 50, 'Supplier': 'Vendor B', 'Item Name (Optional)': 'New Widget', 'Category (Optional)': 'Electronics', 'UoM (Optional)': 'pcs' }
    ]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Inward_Template");
    XLSX.writeFile(wb, "Inward_Bulk_Template.xlsx");
  };

  // Handle Bulk File Upload
  const handleBulkUpload = async () => {
    if (!bulkFile) {
      alert("Please select a file first.");
      return;
    }

    setBulkLoading(true);
    setBulkResult(null);

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const wsname = workbook.SheetNames[0];
        const ws = workbook.Sheets[wsname];
        const jsonData = XLSX.utils.sheet_to_json(ws);

        if (jsonData.length === 0) {
          alert("Sheet is empty!");
          setBulkLoading(false);
          return;
        }

        const entries: InwardEntry[] = jsonData.map((row: any) => {
           // Normalize keys
           const r: any = {};
           Object.keys(row).forEach(key => r[key.toLowerCase().trim()] = row[key]);

           return {
             itemCode: r['item code'] || r['code'] || '',
             quantity: Number(r['quantity'] || r['qty'] || 0),
             supplier: r['supplier'] || r['vendor'] || r['party'] || '',
             newItemDetails: {
               name: r['item name'] || r['name'] || r['item name (optional)'],
               category: r['category'] || r['category (optional)'],
               uom: r['uom'] || r['unit'] || r['uom (optional)']
             }
           };
        });

        const result = await processBulkInward(entries);
        setBulkResult({
          success: result.successCount,
          errors: result.errorCount,
          msg: result.errors
        });

        if (result.successCount > 0 && result.errorCount === 0) {
           setBulkFile(null);
           if (fileInputRef.current) fileInputRef.current.value = '';
        }

      } catch (error) {
        console.error(error);
        alert("Failed to process file.");
      } finally {
        setBulkLoading(false);
      }
    };
    reader.readAsArrayBuffer(bulkFile);
  };

  return (
    <div className="max-w-2xl mx-auto space-y-4">

      {/* Tab Switcher */}
      <div className="bg-white rounded-lg p-1 shadow-sm border border-gray-100 flex">
        <button 
          onClick={() => setActiveTab('single')}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
            activeTab === 'single' 
              ? 'bg-emerald-50 text-emerald-700 shadow-sm' 
              : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
          }`}
        >
          Single Entry
        </button>
        <button 
          onClick={() => setActiveTab('bulk')}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
            activeTab === 'bulk' 
              ? 'bg-emerald-50 text-emerald-700 shadow-sm' 
              : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
          }`}
        >
          Bulk Import (Excel)
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 flex items-center justify-between">
          <h2 className="text-white font-semibold text-lg flex items-center">
            {activeTab === 'single' ? <PlusCircle className="mr-2" /> : <FileSpreadsheet className="mr-2" />}
            {activeTab === 'single' ? 'Inward Stock Entry' : 'Bulk Inward Processing'}
          </h2>
          <span className="text-emerald-100 text-sm bg-emerald-700 px-2 py-1 rounded">
            {new Date().toLocaleDateString()}
          </span>
        </div>

        {activeTab === 'single' ? (
          <form onSubmit={handleSubmit} className="p-6 space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Item Code</label>
                <input 
                  type="text" 
                  list="item-codes"
                  required
                  value={itemCode}
                  onChange={(e) => setItemCode(e.target.value.toUpperCase())}
                  className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  placeholder="Scan or type code"
                />
                <datalist id="item-codes">
                  {items.map(i => <option key={i.code} value={i.code} />)}
                </datalist>
                {isNewItem && itemCode.length > 2 && (
                  <p className="text-xs text-blue-600 mt-1">New Item Detected - Please fill details</p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Item Name</label>
                <input 
                  type="text" 
                  required
                  value={itemName}
                  readOnly={!isNewItem}
                  onChange={(e) => setItemName(e.target.value)}
                  className={`w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none ${!isNewItem ? 'bg-gray-100' : ''}`}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                <select 
                  disabled={!isNewItem}
                  value={category}
                  onChange={(e) => setCategory(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 bg-white disabled:bg-gray-100"
                >
                  {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Unit (UoM)</label>
                 <select
                   disabled={!isNewItem}
                   value={uom}
                   onChange={(e) => setUom(e.target.value)}
                   className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 bg-white disabled:bg-gray-100"
                 >
                    {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
                 </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 border-t pt-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Quantity In</label>
                <input 
                  type="number" 
                  required
                  min="1"
                  value={qty}
                  onChange={(e) => setQty(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                />
                {existingStock !== null && (
                  <p className="text-xs text-gray-500 mt-1">Current Stock: {existingStock}</p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Supplier / Vendor</label>
                <input 
                  type="text" 
                  required
                  value={supplier}
                  onChange={(e) => setSupplier(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:outline-none"
                  placeholder="e.g. Acme Corp"
                />
              </div>
            </div>

            <button 
              type="submit"
              disabled={loading}
              className="w-full mt-4 bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-3 rounded-lg transition-colors flex justify-center items-center disabled:opacity-70"
            >
              {loading ? (
                 <span className="flex items-center">Saving...</span>
              ) : success ? (
                 <span className="flex items-center"><CheckCircle className="mr-2"/> Stock Added Successfully</span>
              ) : (
                 <span className="flex items-center"><Save className="mr-2" size={18}/> Save to Inventory</span>
              )}
            </button>
          </form>
        ) : (
          <div className="p-6 space-y-6">
            <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 text-sm text-blue-800">
              <p className="font-semibold mb-1">Instructions:</p>
              <ul className="list-disc pl-5 space-y-1">
                <li>Download the template below.</li>
                <li>Fill in <strong>Item Code</strong>, <strong>Quantity</strong>, and <strong>Supplier</strong> (Required).</li>
                <li>For new items, also fill Name, Category, and UoM.</li>
                <li>Upload the file to process inward entries in bulk.</li>
              </ul>
            </div>

            <div className="flex flex-col sm:flex-row gap-4">
              <button 
