const SHEET_ID = ""; // Optional: Leave empty if script is bound to the sheet, otherwise paste Sheet ID.

function doGet(e) {
  // SAFEGUARD: Wrap everything in try-catch to ensure JSON is returned even on crash.
  // This prevents "Failed to fetch" CORS errors when the script throws an exception.
  try {
    if (!e || !e.parameter) {
      return ContentService.createTextOutput("SUCCESS: The script is valid. Please Deploy this as a Web App and use the URL.");
    }

    const op = e.parameter.action;

    if (op === 'getItems') {
      return getItems();
    } else if (op === 'getLogs') {
      return getLogs();
    }

    return response({ status: 'error', message: 'Invalid action' });
  } catch (err) {
    return response({ status: 'error', message: err.toString() });
  }
}

function doPost(e) {
  try {
    if (!e || !e.postData) {
      return ContentService.createTextOutput("Error: doPost must be called with JSON data via HTTP POST.");
    }

    const data = JSON.parse(e.postData.contents);
    const action = data.action;

    if (action === 'inward') {
      return handleInward(data);
    } else if (action === 'bulkInward') {
      return handleBulkInward(data);
    } else if (action === 'outward') {
      return handleOutward(data);
    } else if (action === 'addItem') {
      return handleAddItem(data);
    } else if (action === 'updateItem') {
      return handleUpdateItem(data);
    }
    return response({ status: 'error', message: 'Unknown action' });
  } catch (err) {
    return response({ status: 'error', message: err.toString() });
  }
}

// --- Handlers ---

function getItems() {
  const sheet = getSheet('Master');
  if (!sheet) throw new Error("Sheet 'Master' not found. Please run setup() function.");

  const rows = sheet.getDataRange().getValues();
  if (rows.length < 1) return response({ status: 'success', data: [] });

  const headers = rows.shift(); // Remove header

  const items = rows.map(r => ({
    code: r[0],
    name: r[1],
    category: r[2],
    uom: r[3],
    openingStock: Number(r[4]),
    currentStock: Number(r[5])
  })).filter(i => i.code && i.code !== "");

  return response({ status: 'success', data: items });
}

function getLogs() {
  const sheet = getSheet('Logs');
  if (!sheet) throw new Error("Sheet 'Logs' not found. Please run setup() function.");

  const rows = sheet.getDataRange().getValues();
  if (rows.length < 1) return response({ status: 'success', data: [] });

  rows.shift(); // Remove header

  // Sort by date desc (assuming date is col 0) - Limit to last 500 for performance
  const logs = rows.reverse().slice(0, 500).map((r, i) => ({
    id: 'log_' + i,
    date: r[0],
    type: r[1],
    itemCode: r[2],
    itemName: r[3],
    quantity: Number(r[4]),
    partyName: r[5],
    stockAfter: Number(r[6])
  }));

  return response({ status: 'success', data: logs });
}

function handleInward(data) {
  const ss = getSS();
  const master = ss.getSheetByName('Master');
  const logs = ss.getSheetByName('Logs');

  const rows = master.getDataRange().getValues();
  let rowIndex = -1;
  let currentStock = 0;

  // Find Item
  for (let i = 1; i < rows.length; i++) {
    if (rows[i][0] === data.itemCode) {
      rowIndex = i + 1; // 1-based index
      currentStock = Number(rows[i][5]);
      break;
    }
  }

  // If new item details provided and item not found
  if (rowIndex === -1) {
    if (data.newItemDetails) {
       master.appendRow([
         data.itemCode, 
         data.newItemDetails.name, 
         data.newItemDetails.category, 
         data.newItemDetails.uom, 
         0, 
         data.quantity
       ]);
       currentStock = 0; // Opening
    } else {
      throw new Error("Item not found");
    }
  } else {
    // Update existing
    const newStock = currentStock + Number(data.quantity);
    master.getRange(rowIndex, 6).setValue(newStock);
    currentStock = newStock; // For log
  }

  // Log it
  logs.appendRow([
    new Date().toISOString(),
    'INWARD',
    data.itemCode,
    data.newItemDetails ? data.newItemDetails.name : (rowIndex !== -1 ? rows[rowIndex-1][1] : 'Unknown'),
    data.quantity,
    data.supplier,
    rowIndex !== -1 ? (Number(rows[rowIndex-1][5]) + Number(data.quantity)) : data.quantity
  ]);

  return response({ status: 'success', message: 'Inward Processed' });
}

function handleBulkInward(data) {
  // data.entries is array of inward objects
  const ss = getSS();
  const master = ss.getSheetByName('Master');
  const logs = ss.getSheetByName('Logs');
  const masterData = master.getDataRange().getValues();

  let success = 0;
  let errors = [];

  // Map code to row index for O(1) lookup logic
  let codeMap = {};
  for(let i=1; i<masterData.length; i++) {
    codeMap[masterData[i][0]] = i + 1;
  }

  data.entries.forEach((entry, idx) => {
    try {
      let rowIndex = codeMap[entry.itemCode];
      let finalStock = 0;
      let itemName = "";

      if (rowIndex) {
        // Update
        let currentStock = master.getRange(rowIndex, 6).getValue();
        finalStock = Number(currentStock) + Number(entry.quantity);
        master.getRange(rowIndex, 6).setValue(finalStock);
        itemName = master.getRange(rowIndex, 2).getValue();
      } else {
        // Create New
        if (!entry.newItemDetails || !entry.newItemDetails.name) throw new Error("New item details missing");

        master.appendRow([
          entry.itemCode,
          entry.newItemDetails.name,
          entry.newItemDetails.category || 'General',
          entry.newItemDetails.uom || 'pcs',
          0,
          entry.quantity
        ]);
        finalStock = entry.quantity;
        itemName = entry.newItemDetails.name;
        // Update map for subsequent entries of same item in this batch? 
        // For simplicity, we won't re-read sheet, so duplicates in batch might be issue without reload.
        // Assuming unique items in batch or acceptable race condition for simple script.
      }

      logs.appendRow([
        new Date().toISOString(),
        'INWARD',
        entry.itemCode,
        itemName,
        entry.quantity,
        entry.supplier,
        finalStock
      ]);
      success++;
    } catch (e) {
      errors.push(`Row ${idx+1}: ${e.message}`);
    }
  });

  return response({ status: 'success', successCount: success, errorCount: errors.length, errors: errors });
}

function handleOutward(data) {
  const ss = getSS();
  const master = ss.getSheetByName('Master');
  const logs = ss.getSheetByName('Logs');

  const rows = master.getDataRange().getValues();
  let rowIndex = -1;

  for (let i = 1; i < rows.length; i++) {
    if (rows[i][0] === data.itemCode) {
      rowIndex = i + 1;
      break;
    }
  }

  if (rowIndex === -1) throw new Error("Item not found");

  const currentStock = Number(master.getRange(rowIndex, 6).getValue());
  if (currentStock < data.quantity) throw new Error("Insufficient Stock");

  const newStock = currentStock - data.quantity;
  master.getRange(rowIndex, 6).setValue(newStock);

  logs.appendRow([
    new Date().toISOString(),
    'OUTWARD',
    data.itemCode,
    rows[rowIndex-1][1], // Name
    data.quantity,
    data.customer,
    newStock
  ]);

  return response({ status: 'success' });
}

function handleAddItem(data) {
  const sheet = getSheet('Master');
  sheet.appendRow([
    data.item.code,
    data.item.name,
    data.item.category,
    data.item.uom,
    data.item.openingStock,
    data.item.currentStock
  ]);
  return response({ status: 'success' });
}

function handleUpdateItem(data) {
  const sheet = getSheet('Master');
  const rows = sheet.getDataRange().getValues();

  for (let i = 1; i < rows.length; i++) {
    if (rows[i][0] === data.code) {
      // Assuming updates contains fields. For specific column updates:
      const row = i + 1;
      if (data.updates.name) sheet.getRange(row, 2).setValue(data.updates.name);
      if (data.updates.category) sheet.getRange(row, 3).setValue(data.updates.category);
      if (data.updates.uom) sheet.getRange(row, 4).setValue(data.updates.uom);
      if (data.updates.currentStock !== undefined) {
         sheet.getRange(row, 6).setValue(data.updates.currentStock);
      }
      return response({ status: 'success' });
    }
  }
  return response({ status: 'error', message: 'Item not found' });
}

// --- Helpers ---

function getSS() {
  return SHEET_ID ? SpreadsheetApp.openById(SHEET_ID) : SpreadsheetApp.getActiveSpreadsheet();
}

function getSheet(name) {
  return getSS().getSheetByName(name);
}

function response(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function setup() {
  const ss = getSS();

  if (!ss.getSheetByName('Master')) {
    const s = ss.insertSheet('Master');
    s.appendRow(['Item Code', 'Name', 'Category', 'UoM', 'Opening Stock', 'Current Stock']);
  }

  if (!ss.getSheetByName('Logs')) {
    const s = ss.insertSheet('Logs');
    s.appendRow(['Date', 'Type', 'Item Code', 'Name', 'Quantity', 'Party', 'Stock After']);
  }
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Item, LogEntry, TransactionType, InwardEntry } from '../types';

// =========================================================================================
// 🚀 CONFIGURATION: PASTE YOUR GOOGLE WEB APP URL BELOW
// =========================================================================================
const HARDCODED_API_URL = ""; // e.g. "https://script.google.com/macros/s/AKfycbx.../exec"
// =========================================================================================

interface InventoryContextType {
  items: Item[];
  logs: LogEntry[];
  loading: boolean;
  isConnected: boolean;
  connectionError: string | null;
  addItem: (item: Item) => Promise<void>;
  updateItem: (code: string, updates: Partial<Item>) => Promise<void>;
  importItems: (newItems: Item[]) => void;
  processInward: (data: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => Promise<void>;
  processBulkInward: (entries: InwardEntry[]) => Promise<{ successCount: number; errorCount: number; errors: string[] }>;
  processOutward: (data: { itemCode: string; quantity: number; customer: string }) => Promise<void>;
  exportData: () => void;
  adjustStock: (code: string, newQty: number, reason: string) => Promise<void>;
  setConnectionUrl: (url: string) => void;
}

const InventoryContext = createContext<InventoryContextType | undefined>(undefined);

// Mock Initial Data (Fallback)
const INITIAL_ITEMS: Item[] = [
  { code: 'DEMO001', name: 'Demo Laptop (Local)', category: 'Electronics', openingStock: 10, currentStock: 8, uom: 'pcs' },
  { code: 'DEMO002', name: 'Demo Chair (Local)', category: 'Furniture', openingStock: 50, currentStock: 45, uom: 'pcs' },
];

export const InventoryProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // Initialize from Hardcoded OR LocalStorage
  const [apiUrl, setApiUrl] = useState<string>(() => {
    return HARDCODED_API_URL || localStorage.getItem('inventory_api_url') || "";
  });

  const [items, setItems] = useState<Item[]>(INITIAL_ITEMS);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [connectionError, setConnectionError] = useState<string | null>(null);

  // Fetch Data on Load or when URL changes
  useEffect(() => {
    if (apiUrl) {
      fetchData();
    } else {
      console.log('Running in Local Demo Mode. Connect Google Sheet via Settings.');
    }
  }, [apiUrl]);

  const setConnectionUrl = (url: string) => {
    const cleanUrl = url.trim();
    localStorage.setItem('inventory_api_url', cleanUrl);
    setApiUrl(cleanUrl);
    setConnectionError(null);
    if (!cleanUrl) {
      setItems(INITIAL_ITEMS);
      setLogs([]);
    }
  };

  const fetchData = async () => {
    if (!apiUrl) return;
    setLoading(true);
    setConnectionError(null);
    try {
      // Helper to handle response parsing with safeguards
      const fetchJson = async (url: string) => {
        // We use credentials: 'omit' to avoid sending Google cookies that might confuse the script if "Anyone" access is not perfect.
        const res = await fetch(url, { redirect: 'follow', credentials: 'omit' });

        if (!res.ok) throw new Error(`HTTP Error: ${res.status}`);

        const text = await res.text();
        try {
          return JSON.parse(text);
        } catch (e) {
          // If we got HTML (e.g. Google Error page), throw a clear error
          console.error("Non-JSON response received:", text.substring(0, 150));
          if (text.includes("script.google.com")) {
            throw new Error("Script Error: The Google Sheet script returned an error page. Check the script logs.");
          } else if (text.includes("Google Drive")) {
             throw new Error("Permission Error: Ensure the Web App is deployed as 'Anyone'.");
          }
          throw new Error("Invalid response from server.");
        }
      };

      // Add timestamp to prevent caching
      const ts = new Date().getTime();

      // Fetch Items
      const itemsJson = await fetchJson(`${apiUrl}?action=getItems&_t=${ts}`);
      if (itemsJson.status === 'success') {
         setItems(itemsJson.data);
      } else {
         throw new Error(itemsJson.message || "Failed to load items");
      }

      // Fetch Logs
      const logsJson = await fetchJson(`${apiUrl}?action=getLogs&_t=${ts}`);
      if (logsJson.status === 'success') {
         setLogs(logsJson.data);
      }

    } catch (error: any) {
      console.error("Failed to fetch data", error);
      setConnectionError(error.message || "Failed to connect to Google Sheet");
    } finally {
      setLoading(false);
    }
  };

  const postToApi = async (payload: any) => {
    if (!apiUrl) return; 
    setConnectionError(null);

    // Use text/plain to avoid CORS Preflight (OPTIONS)
    const response = await fetch(apiUrl, {
      method: 'POST',
      credentials: 'omit',
      redirect: 'follow',
      headers: {
        "Content-Type": "text/plain;charset=utf-8", 
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
        throw new Error(`API Request Failed: ${response.status}`);
    }

    const text = await response.text();
    let json;
    try {
        json = JSON.parse(text);
    } catch(e) {
        console.warn("Could not parse POST response", e);
        // Sometimes a redirect happens and we get HTML, but action succeeded. 
        // We throw if we can't confirm success, to be safe.
        throw new Error("Invalid response from server during save.");
    }

    if(json.status === 'error') throw new Error(json.message);
    return json;
  };

  const addItem = async (newItem: Item) => {
    if (apiUrl) {
      await postToApi({ action: 'addItem', item: newItem });
      await fetchData(); 
    } else {
      setItems(prev => [...prev, newItem]);
    }
  };

  const updateItem = async (code: string, updates: Partial<Item>) => {
    if (apiUrl) {
      await postToApi({ action: 'updateItem', code, updates });
      await fetchData();
    } else {
      setItems(prev => prev.map(item => item.code === code ? { ...item, ...updates } : item));
    }
  };

  const adjustStock = async (code: string, newQty: number, reason: string) => {
     const currentItem = items.find(i => i.code === code);
     if (!currentItem) return;
     const diff = newQty - currentItem.currentStock;

     if (apiUrl) {
       await postToApi({ action: 'updateItem', code, updates: { currentStock: newQty } });
       await fetchData();
     } else {
        updateItem(code, { currentStock: newQty });
        const newLog: LogEntry = {
          id: Date.now().toString(),
          date: new Date().toISOString(),
          itemCode: code,
          itemName: currentItem.name,
          type: TransactionType.INWARD, 
          quantity: Math.abs(diff),
          partyName: `Adjustment: ${reason}`,
          stockAfter: newQty
        };
        setLogs(prev => [newLog, ...prev]);
     }
  };

  const importItems = (newItems: Item[]) => {
    setItems(prevItems => {
      const itemMap = new Map(prevItems.map(i => [i.code, i]));
      newItems.forEach(item => {
        if (item.code) {
          const existing = itemMap.get(item.code);
          if (existing) {
            itemMap.set(item.code, { ...existing, ...item });
          } else {
            itemMap.set(item.code, item);
          }
        }
      });
      return Array.from(itemMap.values());
    });

    if(apiUrl) alert("Note: Imported items are currently local only. Use 'Inward' to save to Sheet.");
  };

  const processInward = async ({ itemCode, quantity, supplier, newItemDetails }: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => {
    if (apiUrl) {
      await postToApi({ 
        action: 'inward', 
        itemCode, 
        quantity, 
        supplier, 
        newItemDetails 
      });
      await fetchData();
    } else {
      await new Promise(resolve => setTimeout(resolve, 500));
      let currentItem = items.find(i => i.code === itemCode);
      let stockAfter = quantity;

      if (currentItem) {
        stockAfter = currentItem.currentStock + quantity;
        setItems(prev => prev.map(item => item.code === itemCode ? { ...item, currentStock: stockAfter } : item));
      } else if (newItemDetails && newItemDetails.name) {
        const newItem: Item = {
          code: itemCode,
          name: newItemDetails.name!,
          category: newItemDetails.category || 'General',
          uom: newItemDetails.uom || 'pcs',
          openingStock: 0,
          currentStock: quantity
        };
        setItems(prev => [...prev, newItem]);
        currentItem = newItem;
        stockAfter = quantity;
      } else {
        throw new Error("Item not found");
      }

      const newLog: LogEntry = {
        id: Date.now().toString(),
        date: new Date().toISOString(),
        itemCode,
        itemName: currentItem ? currentItem.name : 'Unknown',
        type: TransactionType.INWARD,
        quantity,
        partyName: supplier,
        stockAfter
      };
      setLogs(prev => [newLog, ...prev]);
    }
  };

  const processBulkInward = async (entries: InwardEntry[]) => {
    if (apiUrl) {
      const result = await postToApi({ action: 'bulkInward', entries });
      await fetchData();
      return { 
        successCount: result?.successCount || 0, 
        errorCount: result?.errorCount || 0, 
        errors: result?.errors || [] 
      };
    } else {
      await new Promise(resolve => setTimeout(resolve, 1500));
      let successCount = 0;
      let errorCount = 0;
      const errors: string[] = [];
      const newLogs: LogEntry[] = [];
      let currentItemsMap = new Map(items.map(i => [i.code, i]));

      entries.forEach((entry, index) => {
        try {
          if (!entry.itemCode || !entry.quantity || !entry.supplier) throw new Error(`Row ${index + 1}: Missing fields`);

          const existingItem = currentItemsMap.get(entry.itemCode);
          let stockAfter = entry.quantity;
          let itemName = 'Unknown';

          if (existingItem) {
            stockAfter = existingItem.currentStock + entry.quantity;
            currentItemsMap.set(entry.itemCode, { ...existingItem, currentStock: stockAfter });
            itemName = existingItem.name;
          } else {
            if (entry.newItemDetails && entry.newItemDetails.name) {
               const newItem: Item = {
                 code: entry.itemCode,
                 name: entry.newItemDetails.name,
                 category: entry.newItemDetails.category || 'General',
                 uom: entry.newItemDetails.uom || 'pcs',
                 openingStock: 0,
                 currentStock: entry.quantity
               };
               currentItemsMap.set(entry.itemCode, newItem);
               itemName = newItem.name;
            } else {
              throw new Error(`Row ${index + 1}: Item not found`);
            }
          }

          newLogs.push({
            id: Date.now().toString() + Math.random(),
            date: new Date().toISOString(),
            itemCode: entry.itemCode,
            itemName,
            type: TransactionType.INWARD,
            quantity: entry.quantity,
            partyName: entry.supplier,
            stockAfter
          });
          successCount++;
        } catch (err: any) {
          errorCount++;
          errors.push(err.message);
        }
      });

      setItems(Array.from(currentItemsMap.values()));
      setLogs(prev => [...newLogs, ...prev]);
      return { successCount, errorCount, errors };
    }
  };

  const processOutward = async ({ itemCode, quantity, customer }: { itemCode: string; quantity: number; customer: string }) => {
    if (apiUrl) {
      await postToApi({ action: 'outward', itemCode, quantity, customer });
      await fetchData();
    } else {
      await new Promise(resolve => setTimeout(resolve, 500));
      const currentItem = items.find(i => i.code === itemCode);
      if (!currentItem) throw new Error("Item not found.");
      if (currentItem.currentStock < quantity) throw new Error("Insufficient stock!");

      const stockAfter = currentItem.currentStock - quantity;
      setItems(prev => prev.map(i => i.code === itemCode ? { ...i, currentStock: stockAfter } : i));

      const newLog: LogEntry = {
        id: Date.now().toString(),
        date: new Date().toISOString(),
        itemCode,
        itemName: currentItem.name,
        type: TransactionType.OUTWARD,
        quantity,
        partyName: customer,
        stockAfter
      };
      setLogs(prev => [newLog, ...prev]);
    }
  };

  const exportData = () => {
    const headers = ["Date", "Type", "Item Code", "Name", "Quantity", "Party", "Stock After"];
    const rows = logs.map(log => [
      new Date(log.date).toLocaleString(),
      log.type,
      log.itemCode,
      log.itemName,
      log.quantity,
      log.partyName,
      log.stockAfter
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows.map(e => e.join(","))].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "inventory_logs.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <InventoryContext.Provider value={{ 
      items, 
      logs, 
      loading, 
      isConnected: !!apiUrl,
      connectionError,
      addItem, 
      updateItem, 
      importItems, 
      processInward, 
      processBulkInward, 
      processOutward, 
      exportData, 
      adjustStock,
      setConnectionUrl 
    }}>
      {children}
    </InventoryContext.Provider>
  );
};

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) throw new Error("useInventory must be used within InventoryProvider");
  return context;
};

