                    ) : (
                      <div className="flex justify-center items-center space-x-1">
                        <button 
                          onClick={() => startEdit(item)} 
                          className="text-blue-600 hover:bg-blue-100 p-2 rounded-lg transition-colors"
                          title="Edit Item Details"
