import React, { useState, useEffect, useRef } from 'react';
import { useInventory } from '../context/InventoryContext';
import { LogOut, CheckCircle, AlertCircle, Package, Search, X, ChevronDown } from 'lucide-react';
import { Item } from '../types';

export const OutwardForm: React.FC = () => {
  const { items, processOutward } = useInventory();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form State
  const [itemCode, setItemCode] = useState('');
  const [itemName, setItemName] = useState('');
  const [qty, setQty] = useState('');
  const [customer, setCustomer] = useState('');
  const [currentStock, setCurrentStock] = useState<number>(0);
  const [uom, setUom] = useState('');

  // Search/Dropdown State
  const [searchTerm, setSearchTerm] = useState('');
  const [showDropdown, setShowDropdown] = useState(false);
  const searchContainerRef = useRef<HTMLDivElement>(null);

  // Filter items based on search term
  const filteredItems = items.filter(i => 
    i.code.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setShowDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Auto-fill and Context Validation based on itemCode
  useEffect(() => {
    const foundItem = items.find(i => i.code === itemCode);
    if (foundItem) {
      setItemName(foundItem.name);
      setCurrentStock(foundItem.currentStock);
      setUom(foundItem.uom);

      // If the user hasn't typed a custom search term (e.g. initially selecting), sync search term
      if (!searchTerm) {
         setSearchTerm(`${foundItem.code} - ${foundItem.name}`);
      }

      // Re-validate current quantity against new stock level
      if (qty && Number(qty) > foundItem.currentStock) {
        setError(`Insufficient stock. Only ${foundItem.currentStock} ${foundItem.uom} available.`);
      } else {
        setError(null);
      }
    } else {
      setItemName('');
      setCurrentStock(0);
      setUom('');
      setError(null);
    }
  }, [itemCode, items]);

  const handleSelectItem = (item: Item) => {
    setItemCode(item.code);
    setSearchTerm(`${item.code} - ${item.name}`);
    setShowDropdown(false);
    setError(null);
  };

  const clearSelection = () => {
    setItemCode('');
    setSearchTerm('');
    setQty('');
    setShowDropdown(true); // Re-open dropdown for new search
  };

  const handleQtyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setQty(val);

    // Immediate validation
    if (itemCode && Number(val) > currentStock) {
       setError(`Cannot issue ${val}. Only ${currentStock} ${uom} available.`);
    } else {
       if (error && error.includes("issue")) {
          setError(null);
       }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (Number(qty) > currentStock) {
      setError(`Cannot issue ${qty}. Only ${currentStock} ${uom} available.`);
      return;
    }

    setLoading(true);
    try {
      await processOutward({
        itemCode,
        quantity: Number(qty),
        customer,
      });
      setSuccess(true);

      // Reset form
      setItemCode('');
      setSearchTerm(''); // Clear search too
      setQty('');
      setCustomer('');

      setTimeout(() => setSuccess(false), 3000);
    } catch (err: any) {
      setError(err.message || "Error processing outward");
    } finally {
      setLoading(false);
    }
  };

  const isInvalid = Number(qty) > currentStock;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="bg-orange-600 px-6 py-4 flex items-center justify-between">
        <h2 className="text-white font-semibold text-lg flex items-center">
          <LogOut className="mr-2" /> Outward / Issue Stock
        </h2>
        <span className="text-orange-100 text-sm bg-orange-700 px-2 py-1 rounded">
          {new Date().toLocaleDateString()}
        </span>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        {error && (
          <div className="bg-red-50 text-red-700 p-3 rounded-lg flex items-center text-sm animate-fade-in border border-red-100">
            <AlertCircle size={16} className="mr-2 flex-shrink-0" /> {error}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          {/* Searchable Dropdown */}
          <div className="relative" ref={searchContainerRef}>
            <label className="block text-sm font-medium text-gray-700 mb-2">Search & Select Item</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search className="text-gray-400" size={18} />
              </div>
              <input
                type="text"
                required
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setItemCode(''); // Clear selection if typing triggers change
                  setShowDropdown(true);
                }}
                onFocus={() => setShowDropdown(true)}
                placeholder="Type code or name..."
                className={`w-full pl-10 pr-10 p-2.5 border rounded-lg focus:ring-2 focus:outline-none transition-shadow ${
                   itemCode ? 'border-orange-500 ring-1 ring-orange-500 bg-orange-50' : 'border-gray-300 focus:ring-orange-500'
                }`}
              />
              {itemCode ? (
                <button 
                  type="button" 
                  onClick={clearSelection}
                  className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-red-500"
                >
                  <X size={18} />
                </button>
              ) : (
                <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                  <ChevronDown size={18} />
                </div>
              )}
            </div>

            {/* Dropdown Results */}
            {showDropdown && (
              <div className="absolute z-10 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                {filteredItems.length === 0 ? (
                  <div className="p-3 text-sm text-gray-500 text-center">No items found</div>
                ) : (
                  <ul>
                    {filteredItems.map(item => (
                      <li 
                        key={item.code}
                        onClick={() => handleSelectItem(item)}
                        className={`px-4 py-3 cursor-pointer hover:bg-orange-50 transition-colors border-b border-gray-50 last:border-0 ${
                          item.currentStock === 0 ? 'opacity-60 bg-gray-50' : ''
                        }`}
                      >
                        <div className="flex justify-between items-center">
                          <div>
                            <span className="block font-medium text-gray-800">{item.name}</span>
                            <span className="text-xs text-gray-500">Code: {item.code}</span>
                          </div>
                          <div className={`text-sm font-semibold ${item.currentStock > 0 ? 'text-gray-700' : 'text-red-500'}`}>
                            {item.currentStock} {item.uom}
                          </div>
                        </div>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Item Name (Verified)</label>
            <input 
              type="text" 
              disabled
              value={itemName}
              className="w-full p-2.5 border border-gray-200 rounded-lg bg-gray-100 text-gray-500 cursor-not-allowed"
              placeholder="Auto-populated"
            />
          </div>
        </div>

        {/* Prominent Stock Display */}
        <div className={`p-5 rounded-xl border transition-all duration-300 transform ${
          itemCode 
            ? (currentStock > 0 
                ? 'bg-blue-50 border-blue-200 shadow-sm translate-y-0 opacity-100' 
                : 'bg-red-50 border-red-200 shadow-sm translate-y-0 opacity-100')
            : 'bg-gray-50 border-dashed border-gray-200'
        }`}>
          <div className="flex justify-between items-center">
             <div className="flex items-center space-x-3">
               <div className={`p-2 rounded-full ${itemCode && currentStock > 0 ? 'bg-blue-100 text-blue-600' : 'bg-gray-200 text-gray-400'}`}>
                 <Package size={24} />
               </div>
               <div>
                 <span className={`block text-xs font-semibold uppercase tracking-wide ${itemCode ? 'text-gray-500' : 'text-gray-400'}`}>
                   Available Stock
                 </span>
                 {!itemCode && <span className="text-xs text-gray-400">Search and select an item above</span>}
               </div>
             </div>

             {itemCode && (
               <div className="text-right">
                  <span className={`text-3xl font-bold ${currentStock > 0 ? 'text-blue-700' : 'text-red-600'}`}>
                    {currentStock}
                  </span>
                  <span className="ml-1 text-sm font-medium text-gray-500">{uom}</span>
               </div>
             )}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Quantity Out</label>
            <input 
              type="number" 
              required
              min="1"
              max={currentStock}
              value={qty}
              onChange={handleQtyChange}
              disabled={!itemCode || currentStock === 0}
              className={`w-full p-2.5 border rounded-lg focus:ring-2 focus:outline-none transition-colors ${
                isInvalid && qty 
                  ? 'border-red-500 focus:ring-red-200 bg-red-50' 
                  : 'border-gray-300 focus:ring-orange-500'
              } disabled:bg-gray-100 disabled:cursor-not-allowed`}
              placeholder="0"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Customer / Department</label>
            <input 
              type="text" 
              required
              value={customer}
              onChange={(e) => setCustomer(e.target.value)}
              className="w-full p-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:outline-none"
              placeholder="e.g. Sales Dept"
            />
          </div>
        </div>

        <button 
          type="submit"
          disabled={loading || currentStock === 0 || isInvalid || !itemCode}
          className="w-full mt-2 bg-orange-600 hover:bg-orange-700 text-white font-medium py-3.5 rounded-lg transition-colors flex justify-center items-center disabled:opacity-50 disabled:cursor-not-allowed shadow-sm hover:shadow-md"
        >
          {loading ? (
             <span className="flex items-center">Processing...</span>
          ) : success ? (
             <span className="flex items-center"><CheckCircle className="mr-2"/> Issued Successfully</span>
          ) : (
             <span className="flex items-center"><LogOut className="mr-2" size={18}/> Issue Stock</span>
          )}
        </button>
      </form>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Item, LogEntry, TransactionType, InwardEntry } from '../types';

// =========================================================================================
// 🚀 CONFIGURATION: PASTE YOUR GOOGLE WEB APP URL BELOW
// =========================================================================================
const HARDCODED_API_URL = ""; // e.g. "https://script.google.com/macros/s/AKfycbx.../exec"
// =========================================================================================

interface InventoryContextType {
  items: Item[];
  logs: LogEntry[];
  loading: boolean;
  isConnected: boolean;
  connectionError: string | null;
  addItem: (item: Item) => Promise<void>;
  updateItem: (code: string, updates: Partial<Item>) => Promise<void>;
  importItems: (newItems: Item[]) => void;
  processInward: (data: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => Promise<void>;
  processBulkInward: (entries: InwardEntry[]) => Promise<{ successCount: number; errorCount: number; errors: string[] }>;
  processOutward: (data: { itemCode: string; quantity: number; customer: string }) => Promise<void>;
  exportData: () => void;
  adjustStock: (code: string, newQty: number, reason: string) => Promise<void>;
  setConnectionUrl: (url: string) => void;
}

const InventoryContext = createContext<InventoryContextType | undefined>(undefined);

// Mock Initial Data (Fallback)
const INITIAL_ITEMS: Item[] = [
  { code: 'DEMO001', name: 'Demo Laptop (Local)', category: 'Electronics', openingStock: 10, currentStock: 8, uom: 'pcs' },
  { code: 'DEMO002', name: 'Demo Chair (Local)', category: 'Furniture', openingStock: 50, currentStock: 45, uom: 'pcs' },
];

export const InventoryProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // Initialize from Hardcoded OR LocalStorage
  const [apiUrl, setApiUrl] = useState<string>(() => {
    return HARDCODED_API_URL || localStorage.getItem('inventory_api_url') || "";
  });

  const [items, setItems] = useState<Item[]>(INITIAL_ITEMS);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [connectionError, setConnectionError] = useState<string | null>(null);

  // Fetch Data on Load or when URL changes
  useEffect(() => {
    if (apiUrl) {
      fetchData();
    } else {
      console.log('Running in Local Demo Mode. Connect Google Sheet via Settings.');
    }
  }, [apiUrl]);

  const setConnectionUrl = (url: string) => {
    const cleanUrl = url.trim();
    localStorage.setItem('inventory_api_url', cleanUrl);
    setApiUrl(cleanUrl);
    setConnectionError(null);
    if (!cleanUrl) {
      setItems(INITIAL_ITEMS);
      setLogs([]);
    }
  };

  const fetchData = async () => {
    if (!apiUrl) return;
    setLoading(true);
    setConnectionError(null);
    try {
      // Helper to handle response parsing with safeguards
      const fetchJson = async (url: string) => {
        // We use credentials: 'omit' to avoid sending Google cookies that might confuse the script if "Anyone" access is not perfect.
        const res = await fetch(url, { redirect: 'follow', credentials: 'omit' });

        if (!res.ok) throw new Error(`HTTP Error: ${res.status}`);

        const text = await res.text();
        try {
          return JSON.parse(text);
        } catch (e) {
          // If we got HTML (e.g. Google Error page), throw a clear error
          console.error("Non-JSON response received:", text.substring(0, 150));
          if (text.includes("script.google.com")) {
            throw new Error("Script Error: The Google Sheet script returned an error page. Check the script logs.");
          } else if (text.includes("Google Drive")) {
             throw new Error("Permission Error: Ensure the Web App is deployed as 'Anyone'.");
          }
          throw new Error("Invalid response from server.");
        }
      };

      // Add timestamp to prevent caching
      const ts = new Date().getTime();

      // Fetch Items
      const itemsJson = await fetchJson(`${apiUrl}?action=getItems&_t=${ts}`);
      if (itemsJson.status === 'success') {
         setItems(itemsJson.data);
      } else {
         throw new Error(itemsJson.message || "Failed to load items");
      }

      // Fetch Logs
      const logsJson = await fetchJson(`${apiUrl}?action=getLogs&_t=${ts}`);
      if (logsJson.status === 'success') {
         setLogs(logsJson.data);
      }

    } catch (error: any) {
      console.error("Failed to fetch data", error);
      setConnectionError(error.message || "Failed to connect to Google Sheet");
    } finally {
      setLoading(false);
    }
  };

  const postToApi = async (payload: any) => {
    if (!apiUrl) return; 
    setConnectionError(null);

    // Use text/plain to avoid CORS Preflight (OPTIONS)
    const response = await fetch(apiUrl, {
      method: 'POST',
      credentials: 'omit',
      redirect: 'follow',
      headers: {
        "Content-Type": "text/plain;charset=utf-8", 
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
        throw new Error(`API Request Failed: ${response.status}`);
    }

    const text = await response.text();
    let json;
    try {
        json = JSON.parse(text);
    } catch(e) {
        console.warn("Could not parse POST response", e);
        // Sometimes a redirect happens and we get HTML, but action succeeded. 
        // We throw if we can't confirm success, to be safe.
        throw new Error("Invalid response from server during save.");
    }

    if(json.status === 'error') throw new Error(json.message);
    return json;
  };

  const addItem = async (newItem: Item) => {
    if (apiUrl) {
      await postToApi({ action: 'addItem', item: newItem });
      await fetchData(); 
    } else {
      setItems(prev => [...prev, newItem]);
    }
  };

  const updateItem = async (code: string, updates: Partial<Item>) => {
    if (apiUrl) {
      await postToApi({ action: 'updateItem', code, updates });
      await fetchData();
    } else {
      setItems(prev => prev.map(item => item.code === code ? { ...item, ...updates } : item));
    }
  };

  const adjustStock = async (code: string, newQty: number, reason: string) => {
     const currentItem = items.find(i => i.code === code);
     if (!currentItem) return;
     const diff = newQty - currentItem.currentStock;

     if (apiUrl) {
       await postToApi({ action: 'updateItem', code, updates: { currentStock: newQty } });
       await fetchData();
     } else {
        updateItem(code, { currentStock: newQty });
        const newLog: LogEntry = {
          id: Date.now().toString(),
          date: new Date().toISOString(),
          itemCode: code,
          itemName: currentItem.name,
          type: TransactionType.INWARD, 
          quantity: Math.abs(diff),
          partyName: `Adjustment: ${reason}`,
          stockAfter: newQty
        };
        setLogs(prev => [newLog, ...prev]);
     }
  };

  const importItems = (newItems: Item[]) => {
    setItems(prevItems => {
      // Correctly type the Map to avoid inference issues with .map returning (string | Item)[]
      const itemMap = new Map<string, Item>();
      prevItems.forEach(i => itemMap.set(i.code, i));

      newItems.forEach(item => {
        if (item.code) {
          const existing = itemMap.get(item.code);
          if (existing) {
            itemMap.set(item.code, { ...existing, ...item });
          } else {
            itemMap.set(item.code, item);
          }
        }
      });
      return Array.from(itemMap.values());
    });

    if(apiUrl) alert("Note: Imported items are currently local only. Use 'Inward' to save to Sheet.");
  };

  const processInward = async ({ itemCode, quantity, supplier, newItemDetails }: { itemCode: string; quantity: number; supplier: string; newItemDetails?: Partial<Item> }) => {
    if (apiUrl) {
      await postToApi({ 
        action: 'inward', 
        itemCode, 
        quantity, 
        supplier, 
        newItemDetails 
      });
      await fetchData();
    } else {
      await new Promise(resolve => setTimeout(resolve, 500));
      let currentItem = items.find(i => i.code === itemCode);
      let stockAfter = quantity;

      if (currentItem) {
        stockAfter = currentItem.currentStock + quantity;
        setItems(prev => prev.map(item => item.code === itemCode ? { ...item, currentStock: stockAfter } : item));
      } else if (newItemDetails && newItemDetails.name) {
        const newItem: Item = {
          code: itemCode,
          name: newItemDetails.name!,
          category: newItemDetails.category || 'General',
          uom: newItemDetails.uom || 'pcs',
          openingStock: 0,
          currentStock: quantity
        };
        setItems(prev => [...prev, newItem]);
        currentItem = newItem;
        stockAfter = quantity;
      } else {
        throw new Error("Item not found");
      }

      const newLog: LogEntry = {
        id: Date.now().toString(),
        date: new Date().toISOString(),
        itemCode,
        itemName: currentItem ? currentItem.name : 'Unknown',
        type: TransactionType.INWARD,
        quantity,
        partyName: supplier,
        stockAfter
      };
      setLogs(prev => [newLog, ...prev]);
    }
  };

  const processBulkInward = async (entries: InwardEntry[]) => {
    if (apiUrl) {
      const result = await postToApi({ action: 'bulkInward', entries });
      await fetchData();
      return { 
        successCount: result?.successCount || 0, 
        errorCount: result?.errorCount || 0, 
        errors: result?.errors || [] 
      };
    } else {
      await new Promise(resolve => setTimeout(resolve, 1500));
      let successCount = 0;
      let errorCount = 0;
      const errors: string[] = [];
      const newLogs: LogEntry[] = [];

      // Correctly type the Map to avoid inference issues
      const currentItemsMap = new Map<string, Item>();
      items.forEach(i => currentItemsMap.set(i.code, i));

      entries.forEach((entry, index) => {
        try {
          if (!entry.itemCode || !entry.quantity || !entry.supplier) throw new Error(`Row ${index + 1}: Missing fields`);

          const existingItem = currentItemsMap.get(entry.itemCode);
          let stockAfter = entry.quantity;
          let itemName = 'Unknown';

          if (existingItem) {
            stockAfter = existingItem.currentStock + entry.quantity;
            currentItemsMap.set(entry.itemCode, { ...existingItem, currentStock: stockAfter });
            itemName = existingItem.name;
          } else {
            if (entry.newItemDetails && entry.newItemDetails.name) {
               const newItem: Item = {
                 code: entry.itemCode,
                 name: entry.newItemDetails.name,
                 category: entry.newItemDetails.category || 'General',
                 uom: entry.newItemDetails.uom || 'pcs',
                 openingStock: 0,
                 currentStock: entry.quantity
               };
               currentItemsMap.set(entry.itemCode, newItem);
               itemName = newItem.name;
            } else {
              throw new Error(`Row ${index + 1}: Item not found`);
            }
          }

          newLogs.push({
            id: Date.now().toString() + Math.random(),
            date: new Date().toISOString(),
            itemCode: entry.itemCode,
            itemName,
            type: TransactionType.INWARD,
            quantity: entry.quantity,
            partyName: entry.supplier,
            stockAfter
          });
          successCount++;
        } catch (err: any) {
          errorCount++;
          errors.push(err.message);
        }
      });

      setItems(Array.from(currentItemsMap.values()));
      setLogs(prev => [...newLogs, ...prev]);
      return { successCount, errorCount, errors };
    }
  };

  const processOutward = async ({ itemCode, quantity, customer }: { itemCode: string; quantity: number; customer: string }) => {
    if (apiUrl) {
      await postToApi({ action: 'outward', itemCode, quantity, customer });
      await fetchData();
    } else {
      await new Promise(resolve => setTimeout(resolve, 500));
      const currentItem = items.find(i => i.code === itemCode);
      if (!currentItem) throw new Error("Item not found.");
      if (currentItem.currentStock < quantity) throw new Error("Insufficient stock!");

      const stockAfter = currentItem.currentStock - quantity;
      setItems(prev => prev.map(i => i.code === itemCode ? { ...i, currentStock: stockAfter } : i));

      const newLog: LogEntry = {
        id: Date.now().toString(),
        date: new Date().toISOString(),
        itemCode,
        itemName: currentItem.name,
        type: TransactionType.OUTWARD,
        quantity,
        partyName: customer,
        stockAfter
      };
      setLogs(prev => [newLog, ...prev]);
    }
  };

  const exportData = () => {
    const headers = ["Date", "Type", "Item Code", "Name", "Quantity", "Party", "Stock After"];
    const rows = logs.map(log => [
      new Date(log.date).toLocaleString(),
      log.type,
      log.itemCode,
      log.itemName,
      log.quantity,
      log.partyName,
      log.stockAfter
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows.map(e => e.join(","))].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "inventory_logs.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <InventoryContext.Provider value={{ 
      items, 
      logs, 
      loading, 
      isConnected: !!apiUrl,
      connectionError,
      addItem, 
      updateItem, 
      importItems, 
      processInward, 
      processBulkInward, 
      processOutward, 
      exportData, 
      adjustStock,
      setConnectionUrl 
    }}>
      {children}
    </InventoryContext.Provider>
  );
};

export const useInventory = () => {
  const context = useContext(InventoryContext);
  if (!context) throw new Error("useInventory must be used within InventoryProvider");
  return context;
};
